sql:
SELECT max_load
FROM joints
WHERE joint_name = 'J1';

external_knowledge:
; A 'completed' status may imply that the simulation has finished running and has produced results; 
; The 'type1' simulation type could refer to a specific type of simulation, such as stress testing or longevity testing;
; A maximum load greater than 500 could be significant in the context of joint durability testing;
; An average wear level higher than 0.1 might indicate a certain level of acceptable wear, beyond which the joint may be deemed unreliable.

sql:
SELECT sim_id
FROM simulations
ORDER BY sim_id;

SELECT joint_name, max_load
FROM joints
ORDER BY max_load DESC;
